"""
MCP Server Wrapper for OpenCode ToolManager
Exposes existing tools as MCP primitives for external model integration
"""

import asyncio
from pathlib import Path
from typing import Optional, Any

from mcp.server import Server
from mcp.server.stdio import stdio_server
from mcp import types

# Import your existing components
from .tools import ToolManager, ToolResult
from .config import ToolsConfig


class OpenCodeMCPServer:
    """
    Wraps OpenCode ToolManager as an MCP server
    Exposes filesystem tools for local model integration
    """
    
    def __init__(self, tool_manager: ToolManager):
        self.tool_manager = tool_manager
        self.server = Server("opencode-tools")
        self._register_tools()
        self._register_resources()
    
    def _register_tools(self):
        """Register ToolManager tools as MCP tools"""
        
        # File Read Tool
        @self.server.list_tools()
        async def list_tools() -> list[types.Tool]:
            return [
                types.Tool(
                    name="file_read",
                    description="Read contents of a file within the working directory",
                    inputSchema={
                        "type": "object",
                        "properties": {
                            "file_path": {
                                "type": "string",
                                "description": "Path to file relative to working directory"
                            },
                            "start_line": {
                                "type": "integer",
                                "description": "Optional: Start line number"
                            },
                            "end_line": {
                                "type": "integer",
                                "description": "Optional: End line number"
                            }
                        },
                        "required": ["file_path"]
                    }
                ),
                types.Tool(
                    name="file_write",
                    description="Write content to a file within the working directory",
                    inputSchema={
                        "type": "object",
                        "properties": {
                            "file_path": {
                                "type": "string",
                                "description": "Path to file relative to working directory"
                            },
                            "content": {
                                "type": "string",
                                "description": "Content to write to file"
                            }
                        },
                        "required": ["file_path", "content"]
                    }
                ),
                types.Tool(
                    name="grep_search",
                    description="Search for patterns in files within the working directory",
                    inputSchema={
                        "type": "object",
                        "properties": {
                            "pattern": {
                                "type": "string",
                                "description": "Regex pattern to search for"
                            },
                            "path": {
                                "type": "string",
                                "description": "Path to search (file or directory)"
                            },
                            "file_pattern": {
                                "type": "string",
                                "description": "Optional: File pattern to filter (e.g., '*.py')"
                            },
                            "case_sensitive": {
                                "type": "boolean",
                                "description": "Whether search is case-sensitive",
                                "default": True
                            }
                        },
                        "required": ["pattern", "path"]
                    }
                ),
                types.Tool(
                    name="bash_execute",
                    description="Execute allowed bash commands (git, npm, pip, python, etc.)",
                    inputSchema={
                        "type": "object",
                        "properties": {
                            "command": {
                                "type": "string",
                                "description": "Bash command to execute"
                            }
                        },
                        "required": ["command"]
                    }
                )
            ]
        
        # Call Tool Handler
        @self.server.call_tool()
        async def call_tool(
            name: str, 
            arguments: dict[str, Any]
        ) -> list[types.TextContent | types.ImageContent | types.EmbeddedResource]:
            """Execute tool and return results"""
            
            # Map MCP tool calls to ToolManager
            result: ToolResult = await self.tool_manager.execute_tool(name, **arguments)
            
            if result.success:
                return [
                    types.TextContent(
                        type="text",
                        text=result.output
                    )
                ]
            else:
                # Return error as text with error indicator
                error_msg = f"Error: {result.error}\n\nTool: {name}\nArguments: {arguments}"
                return [
                    types.TextContent(
                        type="text",
                        text=error_msg
                    )
                ]
    
    def _register_resources(self):
        """Register working directory info as MCP resource"""
        
        @self.server.list_resources()
        async def list_resources() -> list[types.Resource]:
            workdir = str(self.tool_manager.working_dir)
            return [
                types.Resource(
                    uri=f"file://{workdir}",
                    name="Working Directory",
                    description=f"Current working directory for tool operations: {workdir}",
                    mimeType="text/plain"
                )
            ]
        
        @self.server.read_resource()
        async def read_resource(uri: str) -> str:
            """Return working directory information"""
            workdir = self.tool_manager.working_dir
            
            # List directory contents securely
            try:
                files = list(workdir.rglob("*"))[:100]  # Limit to first 100
                file_list = "\n".join([f"  {f.relative_to(workdir)}" for f in files if f.is_file()])
                
                return f"""Working Directory: {workdir}
Security Boundary: {self.tool_manager.config.safe_workdir}
Allow Outside: {self.tool_manager.config.allow_outside_workdir}

Files (first 100):
{file_list}
"""
            except Exception as e:
                return f"Working Directory: {workdir}\nError listing files: {e}"
    
    async def run(self):
        """Run the MCP server with STDIO transport"""
        async with stdio_server() as (read_stream, write_stream):
            await self.server.run(
                read_stream,
                write_stream,
                self.server.create_initialization_options()
            )


# Standalone entry point for running as separate process
async def main():
    """Run MCP server as standalone process"""
    from .config import Config, ToolsConfig
    
    # Load config
    config = Config.load("config.yaml")
    tool_manager = ToolManager(config.tools)
    
    # Create and run server
    mcp_server = OpenCodeMCPServer(tool_manager)
    print(f"OpenCode MCP Server starting...")
    print(f"Working directory: {tool_manager.working_dir}")
    print(f"Safe workdir: {config.tools.safe_workdir}")
    await mcp_server.run()


if __name__ == "__main__":
    asyncio.run(main())
